// Route Groupon emails by type based on subject line
// Subject patterns:
//   - "Groupon Booking Tool - Groupon Customer Booking Confirmation" → new_booking
//   - "Groupon Booking Tool - Groupon Customer Cancellation Notification" → cancellation
//   - "Groupon Booking Tool - Groupon Booking Modification Notification" → modification

const subject = ($json.subject || '').trim();

let emailType = 'unknown';

if (/Confirmation/i.test(subject)) {
  emailType = 'new_booking';
} else if (/Cancellation/i.test(subject)) {
  emailType = 'cancellation';
} else if (/Modification/i.test(subject)) {
  emailType = 'modification';
}

return {
  json: {
    ...$json,
    email_type: emailType
  }
};

// Parse Groupon booking confirmation email HTML body
// The HTML body contains plain text with <strong> labels:
//   <strong>Service</strong>: $20 for Magic Mic Comedy Wednesday show ticket - two people
//   <strong>Agenda Name</strong>: (may be empty)
//   <strong>Booking Date & Time</strong>: 2026-03-04, 19:30
//   <strong>Customer Name</strong>: Alex Doyle
//   <strong>Customer Phone Number</strong>: 0477 572 222
//   <strong>Customer Groupon Code</strong>: VS-MCCM-MXNX-FBSJ-7F2Z
//   <strong>Customer Comment</strong>: (may be empty)
// Sidebar section has: Date, Number of participants, Service description
// Customer section has mailto: link with real email

const html = ($json.html || $json.textHtml || $json.body || '').toString();
const text = ($json.text || $json.textPlain || '').toString();
const subject = ($json.subject || '').trim();

// Strip HTML tags for regex matching on the plain-ish text
const stripped = html
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/?(p|div|td|tr|li)[^>]*>/gi, '\n')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&#39;/g, "'")
  .replace(/&quot;/g, '"')
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n');

// --- Service description ---
// Pattern: "Service: $20 for Magic Mic Comedy Wednesday show ticket - two people"
let serviceDescription = '';
const serviceMatch = stripped.match(/Service\s*:\s*(.+?)(?:\n|$)/i) ||
  html.match(/<strong>\s*Service\s*<\/strong>\s*:?\s*(.+?)(?:<br|<\/|\n)/i);
if (serviceMatch) {
  serviceDescription = serviceMatch[1].replace(/<[^>]+>/g, '').trim();
}

// --- Booking Date & Time ---
// Pattern: "Booking Date & Time: 2026-03-04, 19:30"
let eventDate = '';
let eventTime = '';
const dateTimeMatch = stripped.match(/Booking Date\s*(?:&|and)\s*Time\s*:\s*(.+?)(?:\n|$)/i) ||
  html.match(/<strong>\s*Booking Date\s*(?:&amp;|&|and)\s*Time\s*<\/strong>\s*:?\s*(.+?)(?:<br|<\/|\n)/i);
if (dateTimeMatch) {
  const raw = dateTimeMatch[1].replace(/<[^>]+>/g, '').trim();
  // Format: "YYYY-MM-DD, HH:MM" or "YYYY-MM-DD HH:MM"
  const dtParts = raw.match(/(\d{4}-\d{2}-\d{2})[,\s]+([\d:]+)/);
  if (dtParts) {
    eventDate = dtParts[1];
    eventTime = dtParts[2];
    // Ensure time has seconds
    if (eventTime && !eventTime.includes(':00', eventTime.length - 3) && eventTime.split(':').length === 2) {
      eventTime = eventTime + ':00';
    }
  }
}

// --- Customer Name ---
let firstName = '';
let lastName = '';
const nameMatch = stripped.match(/Customer Name\s*:\s*(.+?)(?:\n|$)/i) ||
  html.match(/<strong>\s*Customer Name\s*<\/strong>\s*:?\s*(.+?)(?:<br|<\/|\n)/i);
if (nameMatch) {
  const fullName = nameMatch[1].replace(/<[^>]+>/g, '').trim();
  const nameParts = fullName.split(/\s+/);
  firstName = nameParts[0] || '';
  lastName = nameParts.slice(1).join(' ') || '';
}

// --- Customer Phone Number ---
let customerPhone = '';
const phoneMatch = stripped.match(/Customer Phone Number\s*:\s*(.+?)(?:\n|$)/i) ||
  html.match(/<strong>\s*Customer Phone Number\s*<\/strong>\s*:?\s*(.+?)(?:<br|<\/|\n)/i);
if (phoneMatch) {
  customerPhone = phoneMatch[1].replace(/<[^>]+>/g, '').trim();
}

// --- Customer Groupon Code (booking reference) ---
let grouponCode = '';
const codeMatch = stripped.match(/Customer Groupon Code\s*:\s*(.+?)(?:\n|$)/i) ||
  html.match(/<strong>\s*Customer Groupon Code\s*<\/strong>\s*:?\s*(.+?)(?:<br|<\/|\n)/i);
if (codeMatch) {
  grouponCode = codeMatch[1].replace(/<[^>]+>/g, '').trim();
}

// --- Customer Email (from mailto: link) ---
let customerEmail = '';
const emailMatch = html.match(/mailto:([^"'\s>]+@[^"'\s>]+)/i);
if (emailMatch) {
  customerEmail = emailMatch[1].trim().toLowerCase();
}

// --- Number of participants (from sidebar section) ---
let ticketCount = 1;
const participantsMatch = stripped.match(/Number of participants\s*:?\s*(\d+)/i) ||
  html.match(/Number of participants\s*(?:<[^>]*>\s*)*:?\s*(?:<[^>]*>)*(\d+)/i);
if (participantsMatch) {
  ticketCount = parseInt(participantsMatch[1], 10);
}
if (isNaN(ticketCount) || ticketCount < 1) ticketCount = 1;

// --- Parse price from service description ---
// Format: "$20 for Magic Mic Comedy..." → extract $20
let grossRevenue = 0;
const priceMatch = serviceDescription.match(/\$\s*([\d,.]+)/);
if (priceMatch) {
  grossRevenue = parseFloat(priceMatch[1].replace(/,/g, ''));
}
if (isNaN(grossRevenue)) grossRevenue = 0;

// --- Parse event name from service description ---
// Strip the "$XX for " prefix and ticket type suffix
// "$20 for Magic Mic Comedy Wednesday show ticket - two people" → "Magic Mic Comedy Wednesday show"
let eventName = serviceDescription;
if (eventName) {
  // Remove price prefix: "$20 for "
  eventName = eventName.replace(/^\$[\d,.]+\s+for\s+/i, '');
  // Remove trailing ticket type: " ticket - two people", " ticket - one person", " tickets"
  eventName = eventName.replace(/\s+tickets?\s*[-–].*$/i, '');
  eventName = eventName.replace(/\s+tickets?\s*$/i, '');
  eventName = eventName.trim();
}

return {
  json: {
    event_name: eventName,
    service_description: serviceDescription,
    event_date: eventDate,
    event_time: eventTime,
    first_name: firstName,
    last_name: lastName,
    customer_phone: customerPhone,
    customer_email: customerEmail,
    groupon_code: grouponCode,
    ticket_count: ticketCount,
    gross_revenue: grossRevenue,
    source_email_subject: subject,
    source_email_date: $json.date || ''
  }
};

// Merge the parsed Groupon booking data with the matched event/session
const booking = $('Parse Groupon Booking').item.json;
const matchResult = $input.item.json;

// The RPC returns an array - take the first match
const match = Array.isArray(matchResult) ? matchResult[0] : matchResult;

if (!match || !match.event_id) {
  return {
    json: {
      ...booking,
      event_id: null,
      session_id: null,
      match_status: 'no_match',
      match_message: `No event found matching: ${booking.event_name} on ${booking.event_date}`
    }
  };
}

return {
  json: {
    ...booking,
    event_id: match.event_id,
    session_id: match.session_id || null,
    match_status: 'matched',
    match_message: `Matched to event: ${match.event_name || match.event_id}`
  }
};

// Prepare the final payload for manual_ticket_entries
const booking = $('Merge Match Data').item.json;
const customerResult = $input.item.json;

// Get customer_id from upsert result
const customer = Array.isArray(customerResult) ? customerResult[0] : customerResult;
const customerId = customer?.id || null;

// Groupon Partner ID
const GROUPON_PARTNER_ID = '37c101f1-31c1-41fd-9375-20813b89b194';

// Commission rate: 32%
const COMMISSION_RATE = 32;

return {
  json: {
    event_id: booking.event_id,
    session_id: booking.session_id,
    partner_id: GROUPON_PARTNER_ID,
    ticket_count: booking.ticket_count,
    gross_revenue: booking.gross_revenue,
    commission_rate: COMMISSION_RATE,
    status: 'confirmed',
    entry_date: booking.event_date || new Date().toISOString().split('T')[0],
    first_name: booking.first_name,
    last_name: booking.last_name,
    email: booking.customer_email,
    booking_reference: booking.groupon_code,
    customer_id: customerId,
    source: 'n8n',
    notes: `Groupon import: ${booking.event_name}`,
    reference_id: booking.groupon_code
  }
};

// Parse the Groupon cancellation or modification email to extract the Groupon code
// The HTML body contains the same <strong> label structure as booking confirmations
// We need the Customer Groupon Code to match the existing ticket entry

const html = ($json.html || $json.textHtml || $json.body || '').toString();
const emailType = $json.email_type || 'cancellation';

// Strip HTML tags for regex matching
const stripped = html
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/?(p|div|td|tr|li)[^>]*>/gi, '\n')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&#39;/g, "'")
  .replace(/&quot;/g, '"')
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n');

// --- Customer Groupon Code ---
let grouponCode = '';
const codeMatch = stripped.match(/Customer Groupon Code\s*:\s*(.+?)(?:\n|$)/i) ||
  html.match(/<strong>\s*Customer Groupon Code\s*<\/strong>\s*:?\s*(.+?)(?:<br|<\/|\n)/i);
if (codeMatch) {
  grouponCode = codeMatch[1].replace(/<[^>]+>/g, '').trim();
}

if (!grouponCode) {
  // Fallback: look for the Groupon code pattern anywhere (e.g. VS-XXXX-XXXX-XXXX-XXXX)
  const fallbackMatch = stripped.match(/\b(VS-[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{4})\b/i);
  if (fallbackMatch) {
    grouponCode = fallbackMatch[1].trim();
  }
}

if (!grouponCode) {
  throw new Error(`Could not extract Groupon code from ${emailType} email. Subject: ${$json.subject}`);
}

// Determine the target status
const targetStatus = emailType === 'modification' ? 'modified' : 'cancelled';

return {
  json: {
    groupon_code: grouponCode,
    email_type: emailType,
    target_status: targetStatus,
    source_email_subject: $json.subject || '',
    source_email_date: $json.date || ''
  }
};

// Collect results from both paths and generate import summary
// This node receives items from either the new booking insert or the cancel/modify update
const items = $input.all();
let inserted = 0;
let updated = 0;
let duplicates = 0;
let errors = 0;

for (const item of items) {
  const statusCode = item.json.statusCode || item.json?.headers?.status;
  if (statusCode === 201) {
    inserted++;
  } else if (statusCode === 200) {
    updated++;
  } else if (statusCode === 409) {
    duplicates++;
  } else {
    errors++;
  }
}

return {
  json: {
    summary: 'Groupon Import Complete',
    inserted: inserted,
    updated: updated,
    duplicates_skipped: duplicates,
    errors: errors,
    total_processed: items.length,
    timestamp: new Date().toISOString()
  }
};
